import React from "react"
import { properties } from '../../properties/properties.js'
import Select from 'react-select'
import Popup from 'reactjs-popup'
import 'reactjs-popup/dist/index.css'
import {Tab, Tabs, TabList, TabPanel} from 'react-tabs'
import 'react-tabs/style/react-tabs.css'







class CyberAdmin extends React.Component {


    constructor(props) {
        super(props);
        this.state = { screen: 1, result: [], permission: false, holdoverText: ""
        };

    }




    componentDidMount() {

        this.setState({screen: 0});

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');


        var backUrl = properties.backend + `cyberraptor/algorithms`

        fetch(backUrl, {
          "method": "GET",
          headers: headers
        })
        .then(response => response.json())
        .then(response => {
            this.setState({permission: response.permission})
            this.setState({screen: 1})
            this.setState({holdoverText: response.text})
        })
        .catch(err => {
          console.log(err);
        });

    }



    updateHoText = (event) => {

        console.log(document.getElementById("holdover_text"))


        this.setState({screen: 0});

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');


        var backUrl = properties.backend + `cyberraptor/updatehotext`
        fetch(backUrl, {
          "method": "POST",
          headers: headers, 
          body: JSON.stringify({text: document.getElementById("holdover_text").value})
        })
        .then(response => response.json())
        .then(response => {
            if (response.message != "success") {
                this.setState({screen: 1})
                alert(response.message)

            } else {
                /*
                this.setState({result: response.avaliableAlgorthim})
                this.setState({distributionResult: response.distributionAlgorithm})
                this.setState({mainStep: response.mainStep})
                this.setState({permission: response.permission})
                */
                this.setState({holdoverText: response.text})
                this.setState({screen: 1})


                alert("Text has been updated!")
            }
        })
        .catch(err => {
          console.log(err);
        });
    } 






    render() {


        var header = "Loading ..."
        var content = []
        var borderStyleString = "1px solid black"
        var divStyleString = {marginTop: "10px"}
        var marginTop = "10px"
        var redColor = {color: "red"}
        var divStyleDoubleString = {marginTop: "20px"}



        if (!this.state.permission) {

            content.push(<div>You don't have permission for this application! Please contact Keith Siu - keith.siu@ucsf.edu</div>)

            header = ""
        }





        if (this.state.screen == 1 && this.state.permission) {

             header = ""

            var holdText = this.state.holdoverText


            console.log(this.state)


                content.push(
                        <div>
                            <div style={{marginTop: "50px"}}>         
                                <textarea id="holdover_text" name="holdover_text" rows="10" cols="130"  >
                                    {holdText}
                                </textarea>
                            </div><div style={{marginTop: "20px"}}>
                                <button onClick={this.updateHoText} >Save</button> 

                            </div>
                        </div>
                   )










        }






        return (
            <div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}
            </div>
        );


      }


}


export default CyberAdmin
